# 1. CSS
CSS_MARKER = '</style>'
if '/* Sample strip */' in html:
    print("CSS already patched.")
else:
    pos = html.rfind(CSS_MARKER)
    if pos == -1: sys.exit("ERROR: Cannot find </style>")
    html = html[:pos] + SAMPLE_CSS + '\n' + html[pos:]
    print("CSS injected.")

# 2. HTML
HTML_MARKER = '  <div class="usage-bar">'
if 'sample-section' in html:
    print("HTML already patched.")
else:
    pos = html.find(HTML_MARKER)
    if pos == -1: sys.exit("ERROR: Cannot find usage-bar")
    html = html[:pos] + SAMPLE_HTML + html[pos:]
    print("HTML injected.")

# 3. JS
JS_MARKER = '// ── STATE ──'
